// ─────────────────────────────────────────────
// VHSYS :: service_nf_report
// Rota   : POST /service_nf_report
// Fase 5 : Fluxos NF
// ─────────────────────────────────────────────
// Input  : { data: { source: { itens: [...] } } }
// Output : { message: 'Service NF report processed successfully', services_updated: number } HTTP 201
// Banco  : UPSERT service_nf + enriquecimento com centro de custo
// Chave  : numero_nf + serie_nf + data_emissao + cnpj_prestador
// ─────────────────────────────────────────────

const body = $input.first().json.body || $input.first().json;

if (!body.data) {
  return {
    _valid: false,
    statusCode: 400,
    body: { ok: false, error: 'Missing required field: data' }
  };
}

if (!body.data.source || !body.data.source.itens) {
  return {
    _valid: false,
    statusCode: 400,
    body: { ok: false, error: 'Missing required structure: data.source.itens' }
  };
}

if (!Array.isArray(body.data.source.itens)) {
  return {
    _valid: false,
    statusCode: 400,
    body: { ok: false, error: 'itens must be an array' }
  };
}

const itens = body.data.source.itens;

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'service_nf_report',
  event: 'input_validated',
  itens_count: itens.length,
  level: 'info'
}));

return { _valid: true, itens };

// Decode HTML entities + Transform Service NF data
const ctx = $input.first().json;
const itens = ctx.itens;

// Decode HTML entities recursivamente
function decodeHtml(obj) {
  if (typeof obj === 'string') {
    return obj
      .replace(/&amp;/g,  '&')
      .replace(/&lt;/g,   '<')
      .replace(/&gt;/g,   '>')
      .replace(/&quot;/g, '"')
      .replace(/&#39;/g,  "'")
      .replace(/&#x27;/g, "'")
      .replace(/&#x2F;/g, '/')
      .replace(/&nbsp;/g, ' ');
  }
  if (Array.isArray(obj)) return obj.map(decodeHtml);
  if (typeof obj === 'object' && obj !== null) {
    const out = {};
    for (const k in obj) out[k] = decodeHtml(obj[k]);
    return out;
  }
  return obj;
}

// Helper para converter data
function parseDate(dateStr) {
  if (!dateStr) return null;
  const cleaned = String(dateStr).replace(/[^0-9]/g, '');
  if (cleaned.length === 8) {
    const year1 = cleaned.substring(0, 4);
    const year2 = cleaned.substring(4, 8);
    if (year1.startsWith('20') || year1.startsWith('19')) {
      return `${year1}-${cleaned.substring(4, 6)}-${cleaned.substring(6, 8)}`;
    } else {
      return `${year2}-${cleaned.substring(2, 4)}-${cleaned.substring(0, 2)}`;
    }
  }
  return dateStr;
}

// Helper para converter valor
function parseValue(value) {
  if (!value) return 0;
  const cleaned = String(value).replace(/[^0-9.,]/g, '').replace(',', '.');
  const num = parseFloat(cleaned);
  return isNaN(num) ? 0 : num;
}

// Helper para gerar chave única
function generateKey(item) {
  const numero = String(item.NumeroNFS || item.Numero || '').trim();
  const serie = String(item.SerieNFS || item.Serie || '').trim();
  const dataEmissao = parseDate(item.DataEmissao || item.Data || '');
  const cnpjPrestador = String(item.CnpjPrestador || item.CNPJ || '').replace(/\D/g, '');

  return `${numero}-${serie}-${dataEmissao}-${cnpjPrestador}`;
}

const decodedItens = decodeHtml(itens);

const transformedNFs = decodedItens.map((item, index) => {
  const key = generateKey(item);

  if (!key || key === '---') {
    console.log(JSON.stringify({
      timestamp: new Date().toISOString(),
      route: 'service_nf_report',
      event: 'nf_skipped_invalid_key',
      item_index: index,
      item_data: item,
      level: 'warn'
    }));
    return null;
  }

  return {
    chave_nf: key,
    numero_nf: String(item.NumeroNFS || item.Numero || '').trim(),
    serie_nf: String(item.SerieNFS || item.Serie || '').trim(),
    data_emissao: parseDate(item.DataEmissao || item.Data || ''),
    cnpj_prestador: String(item.CnpjPrestador || item.CNPJ || '').replace(/\D/g, ''),
    razao_social_prestador: String(item.RazaoSocialPrestador || item.Prestador || '').trim(),
    cnpj_tomador: String(item.CnpjTomador || item.CNPJTomador || '').replace(/\D/g, ''),
    razao_social_tomador: String(item.RazaoSocialTomador || item.Tomador || '').trim(),
    valor_servico: parseValue(item.ValorServico || item.Valor || 0),
    valor_deducoes: parseValue(item.ValorDeducoes || 0),
    base_calculo: parseValue(item.BaseCalculo || 0),
    aliquota_iss: parseValue(item.AliquotaISS || 0),
    valor_iss: parseValue(item.ValorISS || 0),
    valor_pis: parseValue(item.ValorPIS || 0),
    valor_cofins: parseValue(item.ValorCOFINS || 0),
    valor_inss: parseValue(item.ValorINSS || 0),
    valor_ir: parseValue(item.ValorIR || 0),
    valor_csll: parseValue(item.ValorCSLL || 0),
    discriminacao_servico: String(item.DiscriminacaoServico || item.Servico || '').trim(),
    codigo_servico: String(item.CodigoServico || '').trim(),
    situacao: String(item.Situacao || item.Status || 'Normal').trim(),
    // Campo para enriquecimento com centro de custo (será preenchido depois)
    id_centro_custo: null
  };
}).filter(nf => nf !== null);

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'service_nf_report',
  event: 'nfs_transformed',
  valid_nfs: transformedNFs.length,
  total_input: decodedItens.length,
  level: 'info'
}));

return transformedNFs;

// Combina dados da NF com enriquecimento de centro de custo
const enrichmentResults = $input.all();
const originalNFs = $('Decode + Transform Service NFs').all();

// Cria mapa de enriquecimento
const enrichmentMap = {};
enrichmentResults.forEach(result => {
  if (result.json && result.json.chave_nf) {
    enrichmentMap[result.json.chave_nf] = result.json.id_centro_custos;
  }
});

// Aplica enriquecimento
const enrichedNFs = originalNFs.map(nfItem => {
  const nf = nfItem.json;
  const centroId = enrichmentMap[nf.chave_nf];

  return {
    ...nf,
    id_centro_custo: centroId || null
  };
});

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'service_nf_report',
  event: 'nfs_enriched',
  enriched_count: enrichedNFs.filter(nf => nf.id_centro_custo).length,
  total_nfs: enrichedNFs.length,
  level: 'info'
}));

return enrichedNFs;

// Conta registros afetados e constrói resposta
const affectedRecords = $input.all()
  .filter(item => item.json && item.json.chave_nf)
  .length;

const enrichedCount = $input.all()
  .filter(item => item.json && item.json.id_centro_custo)
  .length;

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'service_nf_report',
  event: 'service_nf_upserted',
  services_updated: affectedRecords,
  enriched_with_centro_custo: enrichedCount,
  level: 'info'
}));

// statusCode 201 — preserva compatibilidade com Flask original
return {
  statusCode: 201,
  body: {
    message: 'Service NF report processed successfully',
    services_updated: affectedRecords,
    enriched_with_centro_custo: enrichedCount
  }
};

// Erro de validação
const input = $input.first().json;
return {
  statusCode: input.statusCode || 400,
  body: input.body || { ok: false, error: 'Validation failed' }
};

// Erro de banco
const errData = $input.first().json;

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'service_nf_report',
  event: 'db_error',
  message: errData.message || 'Unknown DB error',
  level: 'error'
}));

return {
  statusCode: 500,
  body: { ok: false, error: 'Database error', message: 'Could not process service NF report' }
};

// Return the response data as-is
const response = $input.first().json;
return response;
